import { Command } from 'commander';
import { existsSync, readFileSync } from 'fs';
import { resolve } from 'path';
import { executeEstimate } from './estimate.js';
import { executeOrchestrate } from './orchestrate.js';

interface PhaseRunOptions {
  phase: string;
  dryRun?: boolean;
  skipCpa?: boolean;
  strictCpa?: boolean;
}

interface PhaseSummary {
  phase: string;
  storyCount: number | 'unknown';
  status: 'success' | 'failed';
  estimateLog: string;
  orchestrateLog?: string;
}

function timestampId(): string {
  return new Date().toISOString().replace(/[:.]/g, '-');
}

function logDirForRun(phase: string): string {
  return resolve(process.cwd(), 'orchestrations/logs/cli-phase-runner', `${phase}-${timestampId()}`);
}

function emitPhaseEvent(
  event: 'phase_start' | 'phase_complete' | 'phase_fail',
  payload: Record<string, unknown>,
): void {
  process.stdout.write(`${JSON.stringify({
    event,
    timestamp: new Date().toISOString(),
    source: 'epam-cli',
    ...payload,
  })}\n`);
}

function countStoriesForPhase(phase: string): number | 'unknown' {
  const prdPath = resolve(process.cwd(), 'prd.json');
  if (!existsSync(prdPath)) {
    return 'unknown';
  }

  try {
    const document = JSON.parse(readFileSync(prdPath, 'utf8')) as unknown;
    const visited = new Set<unknown>();

    const countStories = (node: unknown): number => {
      if (!node || typeof node !== 'object') {
        return 0;
      }
      if (visited.has(node)) {
        return 0;
      }
      visited.add(node);

      if (Array.isArray(node)) {
        return node.reduce((sum, item) => sum + countStories(item), 0);
      }

      const record = node as Record<string, unknown>;
      let total = 0;
      const storyArray = Array.isArray(record.stories) ? record.stories : undefined;

      if (storyArray) {
        total += storyArray.filter(item => typeof item === 'object' && item !== null).length;
      }

      for (const [key, value] of Object.entries(record)) {
        if (key === 'stories' && storyArray) {
          continue;
        }
        total += countStories(value);
      }

      return total;
    };

    const findPhase = (node: unknown): Record<string, unknown> | undefined => {
      if (!node || typeof node !== 'object') {
        return undefined;
      }

      if (Array.isArray(node)) {
        for (const item of node) {
          const match = findPhase(item);
          if (match) {
            return match;
          }
        }
        return undefined;
      }

      const record = node as Record<string, unknown>;
      if (record.id === phase) {
        return record;
      }

      for (const value of Object.values(record)) {
        const match = findPhase(value);
        if (match) {
          return match;
        }
      }

      return undefined;
    };

    const matchedPhase = findPhase(document);
    return matchedPhase ? countStories(matchedPhase) : 'unknown';
  } catch {
    return 'unknown';
  }
}

function printSummary(summary: PhaseSummary): void {
  process.stdout.write('\nPhase execution summary\n');
  process.stdout.write(`Phase: ${summary.phase}\n`);
  process.stdout.write(`Story count: ${summary.storyCount}\n`);
  process.stdout.write(`Status: ${summary.status}\n`);
  process.stdout.write(`Estimate log: ${summary.estimateLog}\n`);
  if (summary.orchestrateLog) {
    process.stdout.write(`Orchestration log: ${summary.orchestrateLog}\n`);
  }
}

export function createPhaseCommand(): Command {
  const phase = new Command('phase')
    .description('Phase control plane commands');

  phase.addCommand(
    new Command('run')
      .description('Run estimate, optional CPA pass, and orchestration for a phase')
      .requiredOption('--phase <id>', 'Phase to execute')
      .option('--dry-run', 'Preview execution without writing changes')
      .option('--skip-cpa', 'Skip the CPA contextualisation pass and orchestration CPA gate')
      .option('--strict-cpa', 'Halt if the CPA pass returns review or block gates')
      .action(async (opts: PhaseRunOptions) => {
        const phaseId = opts.phase;
        const logsDir = logDirForRun(phaseId);
        const estimateLog = resolve(logsDir, 'estimate.log');
        const orchestrateLog = resolve(logsDir, 'orchestrate.log');
        const storyCount = countStoriesForPhase(phaseId);

        emitPhaseEvent('phase_start', {
          phase: phaseId,
          dryRun: Boolean(opts.dryRun),
          skipCpa: Boolean(opts.skipCpa),
          strictCpa: Boolean(opts.strictCpa),
          estimateLog,
          orchestrateLog,
          storyCount,
        });

        const estimateResult = await executeEstimate({
          phase: phaseId,
          dryRun: opts.dryRun,
          skipCpa: opts.skipCpa,
          strict: opts.strictCpa,
          logFile: estimateLog,
        });

        if (estimateResult.code !== 0) {
          emitPhaseEvent('phase_fail', {
            phase: phaseId,
            stage: estimateResult.cpa ? 'cpa' : 'estimate',
            code: estimateResult.code,
            estimateLog,
            orchestrateLog,
            storyCount,
            message: estimateResult.message,
          });
          printSummary({
            phase: phaseId,
            storyCount,
            status: 'failed',
            estimateLog,
          });
          process.stderr.write(`Error: ${estimateResult.message ?? 'Estimate phase failed.'}\n`);
          process.exit(estimateResult.code);
        }

        const orchestrateResult = await executeOrchestrate({
          phase: phaseId,
          dryRun: opts.dryRun,
          skipCpa: true,
          strictCpa: opts.strictCpa,
          logFile: orchestrateLog,
        });

        if (orchestrateResult.code !== 0) {
          emitPhaseEvent('phase_fail', {
            phase: phaseId,
            stage: 'orchestrate',
            code: orchestrateResult.code,
            estimateLog,
            orchestrateLog,
            storyCount,
            message: orchestrateResult.message,
          });
          printSummary({
            phase: phaseId,
            storyCount,
            status: 'failed',
            estimateLog,
            orchestrateLog,
          });
          process.stderr.write(`Error: ${orchestrateResult.message ?? 'Orchestration failed.'}\n`);
          process.exit(orchestrateResult.code);
        }

        emitPhaseEvent('phase_complete', {
          phase: phaseId,
          code: 0,
          estimateLog,
          orchestrateLog,
          storyCount,
          status: 'success',
        });
        printSummary({
          phase: phaseId,
          storyCount,
          status: 'success',
          estimateLog,
          orchestrateLog,
        });
        process.exit(0);
      }),
  );

  return phase;
}

import { Command } from 'commander';
import { spawn } from 'child_process';
import { dirname, resolve } from 'path';
import { createWriteStream, existsSync, mkdirSync } from 'fs';

function scriptsDir(): string {
  return resolve(process.cwd(), 'orchestrations/scripts');
}

export interface EstimateOptions {
  phase?: string;
  apply?: boolean;
  refine?: boolean;
  dryRun?: boolean;
  json?: boolean;
  strict?: boolean;
  skipCpa?: boolean;
  reconcile?: boolean;
  logFile?: string;
}

export interface CommandExecutionResult {
  code: number;
  script: string;
  args: string[];
  logFile?: string;
}

export interface EstimateCommandResult {
  code: number;
  phase?: string;
  formula: CommandExecutionResult;
  cpa?: CommandExecutionResult;
  message?: string;
}

function ensureLogDir(logFile?: string): void {
  if (!logFile) {
    return;
  }

  mkdirSync(dirname(logFile), { recursive: true });
}

function runScript(
  script: string,
  args: string[],
  env?: Record<string, string>,
  logFile?: string,
): Promise<number> {
  return new Promise((res, reject) => {
    ensureLogDir(logFile);
    const child = spawn('bash', [script, ...args], {
      stdio: ['inherit', 'pipe', 'pipe'],
      env: { ...process.env, ...env },
    });
    const logStream = logFile ? createWriteStream(logFile, { flags: 'a' }) : undefined;

    child.stdout.on('data', chunk => {
      process.stdout.write(chunk);
      logStream?.write(chunk);
    });
    child.stderr.on('data', chunk => {
      process.stderr.write(chunk);
      logStream?.write(chunk);
    });
    child.on('error', reject);
    child.on('close', code => {
      logStream?.end();
      res(code ?? 1);
    });
  });
}

export async function executeEstimate(opts: EstimateOptions): Promise<EstimateCommandResult> {
  const ESTIMATE_SCRIPT = resolve(scriptsDir(), 'estimate-stories.sh');
  const CPA_SCRIPT = resolve(scriptsDir(), 'contextualize-stories.sh');

  if (!existsSync(ESTIMATE_SCRIPT)) {
    return {
      code: 1,
      phase: opts.phase,
      formula: {
        code: 1,
        script: ESTIMATE_SCRIPT,
        args: [],
        logFile: opts.logFile,
      },
      message: `estimate-stories.sh not found at ${ESTIMATE_SCRIPT}. Run from the epam-cli project root.`,
    };
  }

  if (opts.reconcile) {
    if (!existsSync(CPA_SCRIPT)) {
      return {
        code: 1,
        phase: opts.phase,
        formula: {
          code: 0,
          script: ESTIMATE_SCRIPT,
          args: [],
          logFile: opts.logFile,
        },
        cpa: {
          code: 1,
          script: CPA_SCRIPT,
          args: ['--reconcile'],
          logFile: opts.logFile,
        },
        message: `contextualize-stories.sh not found at ${CPA_SCRIPT}.`,
      };
    }

    const cpaArgs = ['--reconcile'];
    if (opts.dryRun) cpaArgs.push('--dry-run');
    try {
      const cpaCode = await runScript(CPA_SCRIPT, cpaArgs, undefined, opts.logFile);

      return {
        code: cpaCode,
        phase: opts.phase,
        formula: {
          code: 0,
          script: ESTIMATE_SCRIPT,
          args: [],
          logFile: opts.logFile,
        },
        cpa: {
          code: cpaCode,
          script: CPA_SCRIPT,
          args: cpaArgs,
          logFile: opts.logFile,
        },
        message: cpaCode === 0 ? undefined : `CPA reconcile failed (exit ${cpaCode}).`,
      };
    } catch (error) {
      return {
        code: 1,
        phase: opts.phase,
        formula: {
          code: 0,
          script: ESTIMATE_SCRIPT,
          args: [],
          logFile: opts.logFile,
        },
        cpa: {
          code: 1,
          script: CPA_SCRIPT,
          args: cpaArgs,
          logFile: opts.logFile,
        },
        message: `Failed to launch contextualize-stories.sh: ${error instanceof Error ? error.message : String(error)}`,
      };
    }
  }

  const estArgs: string[] = [];
  if (opts.phase) estArgs.push('--phase', opts.phase);
  if (opts.refine) estArgs.push('--refine');
  if (opts.apply) estArgs.push('--apply');
  if (opts.json) estArgs.push('--json');

  let estCode: number;
  try {
    estCode = await runScript(ESTIMATE_SCRIPT, estArgs, undefined, opts.logFile);
  } catch (error) {
    return {
      code: 1,
      phase: opts.phase,
      formula: {
        code: 1,
        script: ESTIMATE_SCRIPT,
        args: estArgs,
        logFile: opts.logFile,
      },
      message: `Failed to launch estimate-stories.sh: ${error instanceof Error ? error.message : String(error)}`,
    };
  }
  if (estCode !== 0) {
    return {
      code: estCode,
      phase: opts.phase,
      formula: {
        code: estCode,
        script: ESTIMATE_SCRIPT,
        args: estArgs,
        logFile: opts.logFile,
      },
      message: `Formula estimation failed (exit ${estCode}). Check ${opts.logFile ?? 'the command output'} for details.`,
    };
  }

  if (opts.skipCpa) {
    if (!opts.json) {
      process.stderr.write('\nCPA pass skipped (--skip-cpa)\n');
    }

    return {
      code: 0,
      phase: opts.phase,
      formula: {
        code: estCode,
        script: ESTIMATE_SCRIPT,
        args: estArgs,
        logFile: opts.logFile,
      },
    };
  }

  if (!existsSync(CPA_SCRIPT)) {
    process.stderr.write('\nWarning: contextualize-stories.sh not found — skipping CPA pass\n');

    return {
      code: 0,
      phase: opts.phase,
      formula: {
        code: estCode,
        script: ESTIMATE_SCRIPT,
        args: estArgs,
        logFile: opts.logFile,
      },
      message: `contextualize-stories.sh not found at ${CPA_SCRIPT}; CPA pass skipped.`,
    };
  }

  const cpaArgs: string[] = [];
  if (opts.phase) cpaArgs.push('--phase', opts.phase);
  if (opts.apply) cpaArgs.push('--apply');
  if (opts.strict) cpaArgs.push('--strict');
  if (opts.dryRun) cpaArgs.push('--dry-run');
  if (opts.json) cpaArgs.push('--json');

  let cpaCode: number;
  try {
    cpaCode = await runScript(CPA_SCRIPT, cpaArgs, undefined, opts.logFile);
  } catch (error) {
    return {
      code: 1,
      phase: opts.phase,
      formula: {
        code: estCode,
        script: ESTIMATE_SCRIPT,
        args: estArgs,
        logFile: opts.logFile,
      },
      cpa: {
        code: 1,
        script: CPA_SCRIPT,
        args: cpaArgs,
        logFile: opts.logFile,
      },
      message: `Failed to launch contextualize-stories.sh: ${error instanceof Error ? error.message : String(error)}`,
    };
  }

  if (cpaCode === 3) {
    process.stderr.write('\nCPA gate: BLOCKED — one or more stories cannot proceed.\n');
    process.stderr.write('Resolve flagged issues, then re-run. Override with --skip-cpa.\n');
  } else if (cpaCode === 2) {
    process.stderr.write('\nCPA gate: REVIEW — some stories have elevated risk.\n');

import { Command } from 'commander';
import { spawn } from 'child_process';
import { dirname, resolve } from 'path';
import { createWriteStream, existsSync, mkdirSync } from 'fs';

export interface OrchestrateOptions {
  phase?: string;
  mode?: string;
  dryRun?: boolean;
  skipCleanup?: boolean;
  skipCpa?: boolean;
  strictCpa?: boolean;
  logFile?: string;
}

export interface OrchestrateCommandResult {
  code: number;
  phase?: string;
  script: string;
  args: string[];
  env: Record<string, string>;
  logFile?: string;
  message?: string;
}

function ensureLogDir(logFile?: string): void {
  if (!logFile) {
    return;
  }

  mkdirSync(dirname(logFile), { recursive: true });
}

function runScript(
  script: string,
  args: string[],
  env?: Record<string, string>,
  logFile?: string,
): Promise<number> {
  return new Promise((res, reject) => {
    ensureLogDir(logFile);
    const child = spawn('bash', [script, ...args], {
      stdio: ['inherit', 'pipe', 'pipe'],
      env: { ...process.env, ...env },
    });
    const logStream = logFile ? createWriteStream(logFile, { flags: 'a' }) : undefined;

    child.stdout.on('data', chunk => {
      process.stdout.write(chunk);
      logStream?.write(chunk);
    });
    child.stderr.on('data', chunk => {
      process.stderr.write(chunk);
      logStream?.write(chunk);
    });
    child.on('error', reject);
    child.on('close', code => {
      logStream?.end();
      res(code ?? 1);
    });
  });
}

export async function executeOrchestrate(opts: OrchestrateOptions): Promise<OrchestrateCommandResult> {
  const ORCHESTRATION_SCRIPT = resolve(
    process.cwd(), 'orchestrations/scripts/run-agent-orchestration.sh',
  );

  if (!existsSync(ORCHESTRATION_SCRIPT)) {
    return {
      code: 1,
      phase: opts.phase,
      script: ORCHESTRATION_SCRIPT,
      args: [],
      env: {},
      logFile: opts.logFile,
      message: `run-agent-orchestration.sh not found at ${ORCHESTRATION_SCRIPT}. Run from the epam-cli project root.`,
    };
  }

  if (opts.mode && !['bash', 'hybrid'].includes(opts.mode)) {
    return {
      code: 1,
      phase: opts.phase,
      script: ORCHESTRATION_SCRIPT,
      args: [],
      env: {},
      logFile: opts.logFile,
      message: `--mode must be "bash" or "hybrid" (got "${opts.mode}").`,
    };
  }

  const args: string[] = [];
  if (opts.phase) args.push('--phase', opts.phase);
  if (opts.mode) args.push('--mode', opts.mode);
  if (opts.dryRun) args.push('--dry-run');
  if (opts.skipCleanup) args.push('--skip-cleanup');

  const env: Record<string, string> = {};
  if (opts.skipCpa) env.SKIP_CPA = '1';
  if (opts.strictCpa) env.STRICT_CPA = '1';

  let code: number;
  try {
    code = await runScript(ORCHESTRATION_SCRIPT, args, env, opts.logFile);
  } catch (error) {
    return {
      code: 1,
      phase: opts.phase,
      script: ORCHESTRATION_SCRIPT,
      args,
      env,
      logFile: opts.logFile,
      message: `Failed to launch run-agent-orchestration.sh: ${error instanceof Error ? error.message : String(error)}`,
    };
  }

  let message: string | undefined;
  if (code === 2) {
    process.stderr.write('\nOrchestration halted: escalated stories require human review.\n');
    message = 'Orchestration halted because escalated stories require human review.';
  } else if (code === 3) {
    process.stderr.write('\nOrchestration halted: CPA gate blocked one or more stories.\n');
    message = 'Orchestration halted because the CPA gate blocked one or more stories.';
  } else if (code !== 0) {
    process.stderr.write(`\nOrchestration failed (exit ${code}).\n`);
    message = `Orchestration failed with exit ${code}.`;
  }

  return {
    code,
    phase: opts.phase,
    script: ORCHESTRATION_SCRIPT,
    args,
    env,
    logFile: opts.logFile,
    message,
  };
}

export function createOrchestrateCommand(): Command {
  return new Command('orchestrate')
    .description('Run multi-agent orchestration for a project phase')
    .option('--phase <id>', 'Phase to execute (default: finops)')
    .option('--mode <mode>', 'Orchestration mode: bash or hybrid', 'bash')
    .option('--dry-run', 'Preview execution plan without running agents')
    .option('--skip-cleanup', 'Keep git worktrees after execution (for debugging)')
    .option('--skip-cpa', 'Skip the CPA pre-pass estimate gate')
    .option('--strict-cpa', 'Halt orchestration on CPA review gates')
    .action(async (opts) => {
      const result = await executeOrchestrate(opts);
      if (result.message && result.code === 1) {
        process.stderr.write(`Error: ${result.message}\n`);
      }
      process.exit(result.code);
    });
}

