 88	  if (added.length > 0) {
 89	    changes.push(`added: ${added.join(', ')}`);
 90	  }
 91	  if (removed.length > 0) {
 92	    changes.push(`removed: ${removed.join(', ')}`);
 93	  }
 94	
 95	  return changes.length > 0 ? changes.join('; ') : 'phase story set no longer matches the approved snapshot';
 96	}
