103	export class PhaseApprovalStore {
104	  constructor(
105	    private readonly logPath: string = DEFAULT_PHASE_APPROVAL_LOG_PATH,
106	  ) {}
107	
108	  getLogPath(): string {
109	    return this.logPath;
110	  }
111	
112	  appendApproval(snapshot: PhaseApprovalSnapshot, approver: PhaseApproverIdentity): PhaseApprovalRecord {
113	    const record: PhaseApprovalRecord = {
114	      schemaVersion: 1,
115	      recordType: 'phase_approval',
116	      approvalStatus: 'approved',
117	      phaseId: snapshot.phaseId,
118	      phaseName: snapshot.phaseName,
119	      approvedAt: new Date().toISOString(),
120	      approver,
121	      storyCount: snapshot.storyIds.length,
122	      storyIds: [...snapshot.storyIds],
123	      storyFingerprint: snapshot.storyFingerprint,
124	      estimates: {
125	        minutes: asNumber(snapshot.estimates.minutes),
126	        cost: asNumber(snapshot.estimates.cost),
127	        tokens: asNumber(snapshot.estimates.tokens),
128	        turns: asNumber(snapshot.estimates.turns),
129	      },
130	      stories: snapshot.stories.map(story => ({
131	        id: story.id,
132	        title: story.title,
133	        estimatedMinutes: asNumber(story.estimatedMinutes),
134	        estimatedCost: asNumber(story.estimatedCost),
135	        estimatedTokens: asNumber(story.estimatedTokens),
136	        estimatedTurns: asNumber(story.estimatedTurns),
137	      })),
138	    };
139	
140	    mkdirSync(dirname(this.logPath), { recursive: true });
141	    appendFileSync(this.logPath, `${JSON.stringify(record)}\n`, 'utf8');
142	    return record;
143	  }
144	
145	  getApprovalStatus(snapshot: PhaseApprovalSnapshot): PhaseApprovalStatus {
146	    const record = this.readLatestApproval(snapshot.phaseId);
147	    if (!record) {
148	      return {
149	        phaseId: snapshot.phaseId,
150	        phaseName: snapshot.phaseName,
151	        status: 'missing',
152	        storyCount: snapshot.storyIds.length,
153	      };
154	    }
155	
156	    if (record.storyFingerprint !== snapshot.storyFingerprint) {
157	      return {
158	        phaseId: snapshot.phaseId,
159	        phaseName: snapshot.phaseName,
160	        status: 'invalidated',
161	        storyCount: snapshot.storyIds.length,
162	        approvedAt: record.approvedAt,
163	        approver: record.approver,
164	        invalidReason: `Approved on ${record.approvedAt}, but the phase story set changed (${diffStoryIds(record.storyIds, snapshot.storyIds)}).`,
165	        record,
166	      };
167	    }
168	
169	    return {
170	      phaseId: snapshot.phaseId,
171	      phaseName: snapshot.phaseName,
172	      status: 'approved',
173	      storyCount: snapshot.storyIds.length,
174	      approvedAt: record.approvedAt,
175	      approver: record.approver,
176	      record,
177	    };
178	  }
179	
180	  private readLatestApproval(phaseId: string): PhaseApprovalRecord | undefined {
181	    const records = this.readRecords();
182	    for (let index = records.length - 1; index >= 0; index -= 1) {
183	      if (records[index]?.phaseId === phaseId) {
184	        return records[index];
185	      }
186	    }
187	    return undefined;
188	  }
189	
190	  private readRecords(): PhaseApprovalRecord[] {
191	    if (!existsSync(this.logPath)) {
192	      return [];
193	    }
194	
195	    const content = readFileSync(this.logPath, 'utf8');
196	    if (content.trim().length === 0) {
197	      return [];
198	    }
199	
200	    return content
201	      .split('\n')
202	      .map(line => line.trim())
203	      .filter(line => line.length > 0)
204	      .flatMap(line => {
205	        try {
206	          const parsed = JSON.parse(line) as unknown;
207	          return isApprovalRecord(parsed) ? [parsed] : [];
208	        } catch {
209	          return [];
210	        }
211	      });
212	  }
213	}

