 74	function findPrdPath(): string | undefined {
 75	  const rootPrdPath = resolve(process.cwd(), 'prd.json');
 76	  if (existsSync(rootPrdPath)) {
 77	    return rootPrdPath;
 78	  }
 79	
 80	  const orchestrationPrdPath = resolve(process.cwd(), 'orchestrations/prd.json');
 81	  if (existsSync(orchestrationPrdPath)) {
 82	    return orchestrationPrdPath;
 83	  }
 84	
 85	  return undefined;
 86	}
