 88	function loadPrdDocument(): PrdDocument | undefined {
 89	  const prdPath = findPrdPath();
 90	  if (!prdPath) {
 91	    return undefined;
 92	  }
 93	
 94	  try {
 95	    return JSON.parse(readFileSync(prdPath, 'utf8')) as PrdDocument;
 96	  } catch {
