101	function normalizeNumber(value: unknown): number {
102	  return typeof value === 'number' && Number.isFinite(value) ? value : 0;
103	}
104	
105	function formatNumber(value: number, digits = 2): string {
106	  return value.toLocaleString('en-US', {
107	    minimumFractionDigits: digits,
108	    maximumFractionDigits: digits,
109	  });
110	}
111	
112	function resolvePhaseStoryIds(document: PrdDocument, phaseId: string): string[] {
113	  const implementationOrder = document.implementationOrder ?? {};
114	  if (Array.isArray(implementationOrder[phaseId])) {
115	    return implementationOrder[phaseId] ?? [];
116	  }
117	
118	  const matchingStory = (document.stories ?? []).find(story => story.id === phaseId);
119	  return matchingStory ? [matchingStory.id] : [];
120	}
121	
122	function buildPhaseSnapshot(phaseId: string): PhaseApprovalSnapshot {
123	  const document = loadPrdDocument();
124	  if (!document) {
125	    throw new Error('Unable to load prd.json. Run from the epam-cli project root.');
126	  }
127	
128	  const storyIds = resolvePhaseStoryIds(document, phaseId);
129	  if (storyIds.length === 0) {
130	    throw new Error(`Phase "${phaseId}" was not found in implementationOrder.`);
131	  }
132	
133	  const storiesById = new Map((document.stories ?? []).map(story => [story.id, story] as const));
134	  const stories = storyIds.map(storyId => {
135	    const story = storiesById.get(storyId);
136	    if (!story) {
137	      throw new Error(`Phase "${phaseId}" references story "${storyId}" but it is missing from prd.json.`);
138	    }
139	
140	    return {
141	      id: story.id,
142	      title: story.title,
143	      estimatedMinutes: normalizeNumber(story.estimatedAiMinutes),
144	      estimatedCost: normalizeNumber(story.estimatedCost),
145	      estimatedTokens: normalizeNumber(story.estimatedTokens),
146	      estimatedTurns: normalizeNumber(story.estimatedTurns),
147	    };
148	  });
149	
150	  const fingerprint = createHash('sha256')
151	    .update(JSON.stringify(storyIds))
152	    .digest('hex');
153	
154	  return {
155	    phaseId,
156	    phaseName: document.phasesConfig?.[phaseId]?.description ?? phaseId,
157	    storyIds,
158	    storyFingerprint: fingerprint,
159	    stories,
160	    estimates: stories.reduce(
161	      (totals, story) => ({
162	        minutes: totals.minutes + story.estimatedMinutes,
163	        cost: totals.cost + story.estimatedCost,
164	        tokens: totals.tokens + story.estimatedTokens,
165	        turns: totals.turns + story.estimatedTurns,
166	      }),
167	      { minutes: 0, cost: 0, tokens: 0, turns: 0 },
168	    ),
169	  };
170	}
