172	function resolveApproverIdentity(): PhaseApproverIdentity {
173	  const preferredIdentity = [
174	    { value: process.env.EPAM_APPROVER, source: 'env:EPAM_APPROVER' },
175	    { value: process.env.GIT_AUTHOR_EMAIL, source: 'env:GIT_AUTHOR_EMAIL' },
176	    { value: process.env.EMAIL, source: 'env:EMAIL' },
177	    { value: process.env.GIT_AUTHOR_NAME, source: 'env:GIT_AUTHOR_NAME' },
178	    { value: process.env.USER, source: 'env:USER' },
179	    { value: process.env.USERNAME, source: 'env:USERNAME' },
180	  ].find(candidate => typeof candidate.value === 'string' && candidate.value.trim().length > 0);
181	
182	  if (preferredIdentity?.value) {
183	    return {
184	      id: preferredIdentity.value,
185	      displayName: preferredIdentity.value,
186	      source: preferredIdentity.source,
187	    };
188	  }
189	
190	  const currentUser = userInfo().username;
191	  return {
192	    id: currentUser,
193	    displayName: currentUser,
194	    source: 'os.userInfo',
195	  };
196	}
