231	function printApprovalPreview(snapshot: PhaseApprovalSnapshot, status: PhaseApprovalStatus): void {
232	  process.stdout.write('\nPhase approval review\n');
233	  process.stdout.write(`Phase: ${snapshot.phaseId}\n`);
234	  process.stdout.write(`Description: ${snapshot.phaseName}\n`);
235	  process.stdout.write(`Story count: ${snapshot.storyIds.length}\n`);
236	  process.stdout.write(
237	    `Estimates: ${formatNumber(snapshot.estimates.minutes)} min, $${formatNumber(snapshot.estimates.cost)}, ${formatNumber(snapshot.estimates.tokens, 0)} tokens, ${formatNumber(snapshot.estimates.turns, 0)} turns\n`,
238	  );
239	
240	  if (status.status === 'approved') {
241	    process.stdout.write(
242	      `Existing approval: ${status.approvedAt} by ${status.approver?.displayName ?? status.approver?.id ?? 'unknown'}\n`,
243	    );
244	  } else if (status.status === 'invalidated') {
245	    process.stdout.write(`Existing approval: invalidated (${status.invalidReason})\n`);
246	  } else {
247	    process.stdout.write('Existing approval: none\n');
248	  }
249	
250	  process.stdout.write('Stories:\n');
251	  for (const story of snapshot.stories) {
252	    process.stdout.write(
253	      `- ${story.id}: ${story.title} [${formatNumber(story.estimatedMinutes)} min, $${formatNumber(story.estimatedCost)}, ${formatNumber(story.estimatedTokens, 0)} tokens, ${formatNumber(story.estimatedTurns, 0)} turns]\n`,
254	    );
255	  }
256	}
