258	async function confirmApproval(): Promise<boolean> {
259	  if (!process.stdin.isTTY || !process.stdout.isTTY) {
260	    throw new Error('Approval confirmation requires an interactive terminal.');
261	  }
262	
263	  const rl = createInterface({
264	    input: process.stdin,
265	    output: process.stdout,
266	  });
267	
268	  try {
269	    const answer = await rl.question('Approve this phase for execution? [y/N] ');
270	    return ['y', 'yes'].includes(answer.trim().toLowerCase());
271	  } finally {
272	    rl.close();
273	  }
274	}
