276	export function createPhaseCommand(): Command {
277	  const approvalStore = new PhaseApprovalStore();
278	  const phase = new Command('phase')
279	    .description('Phase control plane commands');
280	
281	  phase.addCommand(
282	    new Command('approve')
283	      .description('Record explicit human approval for a phase')
284	      .requiredOption('--phase <id>', 'Phase to approve')
285	      .action(async (opts: PhaseApproveOptions) => {
286	        try {
287	          const snapshot = buildPhaseSnapshot(opts.phase);
288	          const status = approvalStore.getApprovalStatus(snapshot);
289	
290	          printApprovalPreview(snapshot, status);
291	          const confirmed = await confirmApproval();
292	          if (!confirmed) {
293	            process.stderr.write('Approval aborted.\n');
294	            process.exit(1);
295	          }
296	
297	          const record = approvalStore.appendApproval(snapshot, resolveApproverIdentity());
298	          process.stdout.write(
299	            `Approval recorded for ${record.phaseId} at ${record.approvedAt} by ${record.approver.displayName}.\n`,
300	          );
301	          process.stdout.write(`Approval log: ${approvalStore.getLogPath()}\n`);
302	          process.exit(0);
303	        } catch (error) {
304	          process.stderr.write(`Error: ${error instanceof Error ? error.message : String(error)}\n`);
305	          process.exit(1);
306	        }
307	      }),
308	  );
309	
310	  phase.addCommand(
311	    new Command('run')
312	      .description('Run estimate, optional CPA pass, and orchestration for a phase')
313	      .requiredOption('--phase <id>', 'Phase to execute')
314	      .option('--dry-run', 'Preview execution without writing changes')
315	      .option('--skip-cpa', 'Skip the CPA contextualisation pass and orchestration CPA gate')
316	      .option('--strict-cpa', 'Halt if the CPA pass returns review or block gates')
317	      .option('--require-approval', 'Require a valid human approval record before execution')
318	      .action(async (opts: PhaseRunOptions) => {
319	        try {
320	          const phaseId = opts.phase;
321	          const logsDir = logDirForRun(phaseId);
322	          const estimateLog = resolve(logsDir, 'estimate.log');
323	          const orchestrateLog = resolve(logsDir, 'orchestrate.log');
324	          const snapshot = buildPhaseSnapshot(phaseId);
325	          const approvalStatus = approvalStore.getApprovalStatus(snapshot);
326	          const storyCount = snapshot.storyIds.length;
327	
328	          if (opts.requireApproval && approvalStatus.status !== 'approved') {
329	            emitPhaseEvent('phase_fail', {
330	              phase: phaseId,
331	              stage: 'approval',
332	              code: 1,
333	              estimateLog,
334	              orchestrateLog,
335	              storyCount,
336	              message: approvalStatus.status === 'invalidated'
337	                ? approvalStatus.invalidReason
338	                : `Phase "${phaseId}" requires human approval before execution.`,
339	              ...approvalEventPayload(approvalStatus),
340	            });
